import os
import torch
import torchaudio
import torchaudio.functional as F
from torch.utils.data import Dataset
import random

class ASVspoofDataset(Dataset):
    def __init__(self, protocol_file, flac_dir, is_train=True, max_len=64000):
        self.flac_dir = flac_dir
        self.is_train = is_train
        self.max_len = max_len
        self.data = []

        with open(protocol_file, 'r') as f:
            for line in f:
                parts = line.strip().split()
                if len(parts) == 5:
                    spk, utt, env, attack, label = parts
                    self.data.append({
                        'utt': utt,
                        'label': 1 if label == 'bonafide' else 0
                    })

        if not self.is_train:
            self.data.sort(key=lambda x: os.path.getsize(os.path.join(self.flac_dir, f"{x['utt']}.flac")))

    def __len__(self):
        return len(self.data)

    def __getitem__(self, idx):
        item = self.data[idx]
        filepath = os.path.join(self.flac_dir, f"{item['utt']}.flac")
        waveform, sr = torchaudio.load(filepath)
        waveform = waveform.squeeze(0)

        if self.is_train:
            if waveform.shape[0] > self.max_len:
                start = random.randint(0, waveform.shape[0] - self.max_len)
                waveform = waveform[start:start+self.max_len]
            else:
                pad_len = self.max_len - waveform.shape[0]
                waveform = torch.nn.functional.pad(waveform, (0, pad_len))

            if random.random() < 0.5:
                noise_level = random.uniform(0.0001, 0.005)
                waveform = waveform + torch.randn_like(waveform) * noise_level

            if random.random() < 0.3:
                scale = random.uniform(0.5, 1.5)
                waveform = waveform * scale

            if random.random() < 0.3:
                cut_len = random.randint(1000, 5000)
                start = random.randint(0, waveform.shape[0] - cut_len)
                waveform[start:start+cut_len] = 0

            if random.random() < 0.3:
                aug_type = random.randint(0, 2)
                if aug_type == 0:
                    cutoff = random.uniform(2000, 4000)
                    waveform = F.lowpass_biquad(waveform, 16000, cutoff)
                elif aug_type == 1:
                    cutoff = random.uniform(100, 500)
                    waveform = F.highpass_biquad(waveform, 16000, cutoff)
                else:
                    waveform = F.lowpass_biquad(waveform, 16000, 3400)
                    waveform = F.highpass_biquad(waveform, 16000, 300)

        return waveform, item['label'], item['utt']

def collate_fn(batch):
    waveforms, labels, utts = zip(*batch)
    lengths = torch.tensor([w.shape[0] for w in waveforms])
    max_len = lengths.max().item()

    padded_waveforms = torch.zeros(len(waveforms), max_len)
    for i, w in enumerate(waveforms):
        padded_waveforms[i, :w.shape[0]] = w

    labels = torch.tensor(labels, dtype=torch.float32)
    return padded_waveforms, labels, utts
